Perplexity is a measure of how well a model predicts a test set. It's defined as 2 raised to the power of the negative log-likelihood of the test set. Here's how you can add an option to compute the perplexity of a test set:

```python
import math
import numpy as np

class LanguageModel:
    def __init__(self, vocabulary_size, smoothing=0):
        self.vocabulary_size = vocabulary_size
        self.smoothing = smoothing

    def train(self, training_data):
        # Assuming training data is a list of words
        self.word_counts = {}
        for word in training_data:
            if word in self.word_counts:
                self.word_counts[word] += 1
            else:
                self.word_counts[word] = 1

    def compute_likelihood(self, test_data):
        # Assuming test data is a list of words
        likelihood = 0
        for word in test_data:
            if word in self.word_counts:
                likelihood += math.log(self.word_counts[word] + self.smoothing) - math.log(self.vocabulary_size + self.smoothing)
            else:
                likelihood += math.log(self.smoothing) - math.log(self.vocabulary_size + self.smoothing)

